132	export function planLinePatternDashWorldUnits(
133	  token: string | null | undefined,
134	): { dashSize: number; gapSize: number } | null {
135	  const t = (token ?? 'solid') as PlanLinePatternToken;
136	  switch (t) {
137	    case 'solid':
138	      return null;
139	    case 'dash_short':
140	      return { dashSize: 0.06, gapSize: 0.04 };
141	    case 'dash_long':
142	      return { dashSize: 0.12, gapSize: 0.06 };
143	    case 'dot':
144	      return { dashSize: 0.02, gapSize: 0.05 };
145	    default:
146	      return null;
147	  }
148	}
