220	export function segmentDir(wall: Extract<Element, { kind: 'wall' }>) {
221	  const dx = ux(wall.end.xMm - wall.start.xMm);
222	
223	  const dz = uz(wall.end.yMm - wall.start.yMm);
224	
225	  const len = Math.max(1e-6, Math.hypot(dx, dz));
226	
227	  return {
228	    lenM: len,
229	
230	    nx: dx / len,
231	
232	    nz: dz / len,
233	  };
234	}
