236	export function centroidMm(poly: Array<{ xMm: number; yMm: number }>): {
237	  xMm: number;
238	  yMm: number;
239	} {
240	  let sx = 0;
241	
242	  let sy = 0;
243	
244	  for (const p of poly) {
245	    sx += p.xMm;
246	
247	    sy += p.yMm;
248	  }
249	
250	  const n = Math.max(1, poly.length);
251	
252	  return { xMm: sx / n, yMm: sy / n };
253	}
