255	export function polygonAreaMm2(poly: Array<{ xMm: number; yMm: number }>): number {
256	  let a = 0;
257	
258	  const n = poly.length;
259	
260	  if (n < 3) return 0;
261	
262	  for (let i = 0; i < n; i++) {
263	    const p = poly[i]!;
264	
265	    const q = poly[(i + 1) % n]!;
266	
267	    a += p.xMm * q.yMm - q.xMm * p.yMm;
268	  }
269	
270	  return Math.abs(a / 2);
271	}
