273	/** 45° diagonal hatch lines clipped to an arbitrary polygon outline (mm coords).
274	 * Uses proper edge-intersection scanline — no AABB bleed at polygon corners. */
275	function hatchPolygon2D(
276	  pts: Array<{ xMm: number; yMm: number }>,
277	  spacingMm: number,
278	  yWorld: number,
279	  color: string,
280	  opacity: number,
281	): THREE.LineSegments | null {
282	  const n = pts.length;
283	  if (n < 3) return null;
284	  let minC = Infinity,
285	    maxC = -Infinity;
286	  for (const p of pts) {
287	    const c = p.xMm - p.yMm;
288	    if (c < minC) minC = c;
289	    if (c > maxC) maxC = c;
290	  }
291	  const positions: number[] = [];
292	  for (let c = minC; c <= maxC; c += spacingMm) {
293	    const xs: number[] = [];
294	    for (let i = 0; i < n; i++) {
295	      const p1 = pts[i]!;
296	      const p2 = pts[(i + 1) % n]!;
297	      const dx = p2.xMm - p1.xMm;
298	      const dy = p2.yMm - p1.yMm;
299	      const denom = dx - dy;
300	      if (Math.abs(denom) < 1e-6) continue;
301	      const t = (c - p1.xMm + p1.yMm) / denom;
302	      if (t < -1e-9 || t > 1 + 1e-9) continue;
303	      xs.push(p1.xMm + t * dx);
304	    }
305	    xs.sort((a, b) => a - b);
306	    for (let j = 0; j + 1 < xs.length; j += 2) {
307	      const x0 = xs[j]!;
308	      const x1 = xs[j + 1]!;
309	      positions.push(ux(x0), yWorld, uz(x0 - c), ux(x1), yWorld, uz(x1 - c));
310	    }
311	  }
312	  if (positions.length === 0) return null;
313	  const geo = new THREE.BufferGeometry();
314	  geo.setAttribute('position', new THREE.BufferAttribute(new Float32Array(positions), 3));
315	  const mat = new THREE.LineBasicMaterial({
316	    color: new THREE.Color(color),
317	    transparent: true,
318	    opacity,
319	    depthTest: false,
320	  });
321	  const lines = new THREE.LineSegments(geo, mat);
322	  lines.renderOrder = 5;
323	  return lines;
324	}
