326	function horizontalOutlineMesh(
327	  outlineMm: Array<{ xMm: number; yMm: number }>,
328	  yWorld: number,
329	  color: string,
330	  opacity: number,
331	  pickId: string,
332	): THREE.Mesh {
333	  const shape = new THREE.Shape();
334	
335	  const o = outlineMm[0];
336	
337	  if (!o) return new THREE.Mesh();
338	
339	  shape.moveTo(ux(o.xMm), -uz(o.yMm));
340	
341	  for (let i = 1; i < outlineMm.length; i++) {
342	    const p = outlineMm[i];
343	
344	    if (p) shape.lineTo(ux(p.xMm), -uz(p.yMm));
345	  }
346	
347	  shape.closePath();
348	
349	  const geo = new THREE.ShapeGeometry(shape);
350	
351	  const mesh = new THREE.Mesh(
352	    geo,
353	
354	    new THREE.MeshBasicMaterial({
355	      color,
356	
357	      transparent: true,
358	
359	      opacity,
360	
361	      depthWrite: false,
362	    }),
363	  );
364	
365	  mesh.rotation.x = -Math.PI / 2;
366	
367	  mesh.position.y = yWorld;
368	
369	  mesh.userData.bimPickId = pickId;
370	
371	  return mesh;
372	}
