378	/** Wire-path floor/roof: category-weighted fill + closed outline stroke (pattern from server). */
379	function planFloorRoofOutlineWireGroup(
380	  outlineMm: Array<{ xMm: number; yMm: number }>,
381	  opts: {
382	    kind: 'floor' | 'roof';
383	    pickId: string;
384	    lineWeightHint: number;
385	    linePatternToken?: string | null;
386	    roofGeometrySupportToken?: string | null;
387	    showFill?: boolean;
388	    showHatch?: boolean;
389	  },
390	): THREE.Group {
391	  const grp = new THREE.Group();
392	  const palette = getPlanPalette();
393	  const color = opts.kind === 'floor' ? palette.floorOutline : palette.roofOutline;
394	  const fillY = opts.kind === 'floor' ? PLAN_Y + 0.001 : PLAN_Y + 0.004;
395	  const strokeY = fillY + 0.0004;
396	  const baseOp = opts.kind === 'floor' ? PLAN_FLOOR_FILL_OPACITY_BASE : PLAN_ROOF_FILL_OPACITY_BASE;
397	  const lwh =
398	    Number.isFinite(opts.lineWeightHint) && opts.lineWeightHint > 0 ? opts.lineWeightHint : 1;
399	  const fillOpacity = Math.min(0.65, Math.max(0.12, baseOp * Math.min(1.35, lwh / 1.12)));
400	  const showFill = opts.showFill !== false;
401	  const showHatch = opts.showHatch === true;
402	  if (showFill) {
403	    grp.add(horizontalOutlineMesh(outlineMm, fillY, color, fillOpacity, opts.pickId));
404	  }
405	
406	  // Explicit floor hatch only. Normal plan projection should not synthesize
407	  // slab hatching; it competes with room schemes and can reappear during
408	  // projection refetches after authoring commands.
409	  if (showHatch && opts.kind === 'floor' && outlineMm.length >= 3) {
410	    const hatch = hatchPolygon2D(
411	      outlineMm,
412	      500,
413	      fillY + 0.002,
414	      readToken('--draft-cut', '#1d2330'),
415	      0.12,
416	    );
417	    if (hatch) grp.add(hatch);
418	  }
419	
420	  if (outlineMm.length < 2) {
421	    grp.userData.bimPickId = opts.pickId;
422	    if (opts.kind === 'roof' && opts.roofGeometrySupportToken) {
423	      grp.userData.bimAiRoofGeometrySupportToken = opts.roofGeometrySupportToken;
424	    }
425	    return grp;
426	  }
427	
428	  const pts = outlineMm.map((p) => new THREE.Vector3(ux(p.xMm), strokeY, uz(p.yMm)));
429	  const dashSpec = planLinePatternDashWorldUnits(opts.linePatternToken ?? undefined);
430	  if (dashSpec == null) {
431	    const loop = new THREE.LineLoop(
432	      new THREE.BufferGeometry().setFromPoints(pts),
433	      new THREE.LineBasicMaterial({ color, depthTest: true }),
434	    );
435	    loop.userData.bimPickId = opts.pickId;
436	    grp.add(loop);
437	  } else {
438	    const closed = [...pts, pts[0]!];
439	    const mat = new THREE.LineDashedMaterial({
440	      color,
441	      dashSize: dashSpec.dashSize,
442	      gapSize: dashSpec.gapSize,
443	      depthTest: true,
444	    });
445	    const ln = new THREE.Line(new THREE.BufferGeometry().setFromPoints(closed), mat);
446	    ln.computeLineDistances();
447	    ln.userData.bimPickId = opts.pickId;
448	    grp.add(ln);
449	  }
450	
451	  grp.userData.bimPickId = opts.pickId;
452	  if (opts.kind === 'roof' && opts.roofGeometrySupportToken) {
453	    grp.userData.bimAiRoofGeometrySupportToken = opts.roofGeometrySupportToken;
454	  }
455	  return grp;
456	}
