469	function wallElemFromWirePrimitive(
470	  row: Record<string, unknown>,
471	): Extract<Element, { kind: 'wall' }> {
472	  const lwh = Number(row.lineWeightHint ?? 1);
473	  const baseT = Number(row.thicknessMm ?? 200);
474	  const scale = Number.isFinite(lwh) && lwh > 0 && lwh <= 3 ? lwh : 1;
475	  const joinDisallowStart =
476	    typeof row.joinDisallowStart === 'boolean' ? row.joinDisallowStart : undefined;
477	  const joinDisallowEnd =
478	    typeof row.joinDisallowEnd === 'boolean' ? row.joinDisallowEnd : undefined;
479	  return {
480	    kind: 'wall',
481	    id: String(row.id ?? ''),
482	    name: 'Wall',
483	    levelId: String(row.levelId ?? ''),
484	    start: coerceVec2Mm(row.startMm),
485	    end: coerceVec2Mm(row.endMm),
486	    thicknessMm: baseT * scale,
487	    heightMm: Number(row.heightMm ?? 2800),
488	    ...(joinDisallowStart !== undefined ? { joinDisallowStart } : {}),
489	    ...(joinDisallowEnd !== undefined ? { joinDisallowEnd } : {}),
490	  };
491	}
