521	function roomSeparationLineFromMm(
522	  start: { xMm: number; yMm: number },
523	  end: { xMm: number; yMm: number },
524	  id: string,
525	  linePatternToken?: string | null,
526	): THREE.Line {
527	  const pts = [
528	    new THREE.Vector3(ux(start.xMm), PLAN_Y + 0.003, uz(start.yMm)),
529	    new THREE.Vector3(ux(end.xMm), PLAN_Y + 0.003, uz(end.yMm)),
530	  ];
531	  const geo = new THREE.BufferGeometry().setFromPoints(pts);
532	  const tok =
533	    linePatternToken === undefined || linePatternToken === null || linePatternToken === ''
534	      ? 'dash_short'
535	      : linePatternToken;
536	  const dashSpec = planLinePatternDashWorldUnits(tok);
537	  if (dashSpec == null) {
538	    const line = new THREE.Line(
539	      geo,
540	      new THREE.LineBasicMaterial({
541	        color: getPlanPalette().roomBoundary,
542	        linewidth: 1,
543	        depthTest: true,
544	      }),
545	    );
546	    line.userData.bimPickId = id;
547	    return line;
548	  }
549	  const mat = new THREE.LineDashedMaterial({
550	    color: getPlanPalette().roomBoundary,
551	    dashSize: dashSpec.dashSize,
552	    gapSize: dashSpec.gapSize,
553	    depthTest: true,
554	  });
555	  const line = new THREE.Line(geo, mat);
556	  line.computeLineDistances();
557	  line.userData.bimPickId = id;
558	  return line;
559	}
