561	function gridLineThreeFromPlanWire(
562	  gl: Extract<Element, { kind: 'grid_line' }>,
563	  linePatternToken?: string | null,
564	): THREE.Group {
565	  const grp = new THREE.Group();
566	
567	  const pts = [
568	    new THREE.Vector3(ux(gl.start.xMm), PLAN_Y, uz(gl.start.yMm)),
569	
570	    new THREE.Vector3(ux(gl.end.xMm), PLAN_Y, uz(gl.end.yMm)),
571	  ];
572	
573	  const dashSpec = planLinePatternDashWorldUnits(linePatternToken ?? undefined);
574	  if (dashSpec == null) {
575	    grp.add(
576	      new THREE.Line(
577	        new THREE.BufferGeometry().setFromPoints(pts),
578	
579	        new THREE.LineBasicMaterial({ color: getPlanPalette().dimWitness, linewidth: 2 }),
580	      ),
581	    );
582	  } else {
583	    const mat = new THREE.LineDashedMaterial({
584	      color: getPlanPalette().dimWitness,
585	      dashSize: dashSpec.dashSize,
586	      gapSize: dashSpec.gapSize,
587	      depthTest: true,
588	    });
589	    const ln = new THREE.Line(new THREE.BufferGeometry().setFromPoints(pts), mat);
590	    ln.computeLineDistances();
591	    grp.add(ln);
592	  }
593	
