1000	/**
1001	 * VIE-03: model bounds (walls + floors + roofs) used to anchor an elevation
1002	 * marker on the corresponding bounding-box edge.
1003	 */
1004	export function modelXyBoundsMm(
1005	  elementsById: Record<string, Element>,
1006	): { minXmm: number; minYmm: number; maxXmm: number; maxYmm: number } | null {
1007	  const xs: number[] = [];
1008	  const ys: number[] = [];
1009	  const pushWallCurveBounds = (wall: Extract<Element, { kind: 'wall' }>) => {
1010	    const curve = wall.wallCurve;
1011	    if (!curve || curve.kind !== 'arc') return;
1012	    const sweepRad = THREE.MathUtils.degToRad(curve.sweepDeg);
1013	    const startRad = THREE.MathUtils.degToRad(curve.startAngleDeg);
1014	    const steps = Math.max(8, Math.ceil(Math.abs(sweepRad) / (Math.PI / 24)));
1015	    const radiusMm = curve.radiusMm + wall.thicknessMm / 2;
1016	    for (let i = 0; i <= steps; i++) {
1017	      const a = startRad + (sweepRad * i) / steps;
1018	      xs.push(curve.center.xMm + Math.cos(a) * radiusMm);
1019	      ys.push(curve.center.yMm + Math.sin(a) * radiusMm);
1020	    }
1021	  };
1022	  for (const el of Object.values(elementsById)) {
1023	    if (el.kind === 'wall') {
1024	      xs.push(el.start.xMm, el.end.xMm);
1025	      ys.push(el.start.yMm, el.end.yMm);
1026	      pushWallCurveBounds(el);
1027	    } else if (el.kind === 'floor') {
1028	      for (const p of el.boundaryMm) {
1029	        xs.push(p.xMm);
1030	        ys.push(p.yMm);
1031	      }
1032	    } else if (el.kind === 'roof') {
1033	      for (const p of el.footprintMm) {
1034	        xs.push(p.xMm);
1035	        ys.push(p.yMm);
1036	      }
1037	    }
1038	  }
1039	  if (xs.length === 0 || ys.length === 0) return null;
1040	  return {
1041	    minXmm: Math.min(...xs),
1042	    minYmm: Math.min(...ys),
1043	    maxXmm: Math.max(...xs),
1044	    maxYmm: Math.max(...ys),
1045	  };
1046	}
1047	
1048	/**
1049	 * VIE-03: anchor point + view direction for an elevation_view marker, in mm.
1050	 * `anchor` sits on the bounding-box edge facing the viewer; `viewX/viewY` is
1051	 * the unit vector from the viewer toward the model (also the triangle's tip
1052	 * direction).
1053	 */
1054	export function elevationMarkerAnchorMm(
1055	  ev: Extract<Element, { kind: 'elevation_view' }>,
1056	  bounds: { minXmm: number; minYmm: number; maxXmm: number; maxYmm: number },
1057	  marginMm = 1500,
1058	): { anchorXmm: number; anchorYmm: number; viewX: number; viewY: number } {
1059	  const cx = 0.5 * (bounds.minXmm + bounds.maxXmm);
1060	  const cy = 0.5 * (bounds.minYmm + bounds.maxYmm);
1061	  switch (ev.direction) {
1062	    case 'north':
1063	      return { anchorXmm: cx, anchorYmm: bounds.maxYmm + marginMm, viewX: 0, viewY: -1 };
1064	    case 'south':
1065	      return { anchorXmm: cx, anchorYmm: bounds.minYmm - marginMm, viewX: 0, viewY: 1 };
1066	    case 'east':
1067	      return { anchorXmm: bounds.maxXmm + marginMm, anchorYmm: cy, viewX: -1, viewY: 0 };
1068	    case 'west':
1069	      return { anchorXmm: bounds.minXmm - marginMm, anchorYmm: cy, viewX: 1, viewY: 0 };
1070	    case 'custom': {
1071	      const ang = ((ev.customAngleDeg ?? 0) * Math.PI) / 180;
1072	      const radius =
1073	        Math.max(bounds.maxXmm - bounds.minXmm, bounds.maxYmm - bounds.minYmm) / 2 + marginMm;
1074	      // Viewer stands along +ang from centroid; view direction points back at centroid.
1075	      return {
1076	        anchorXmm: cx + Math.cos(ang) * radius,
1077	        anchorYmm: cy + Math.sin(ang) * radius,
1078	        viewX: -Math.cos(ang),
1079	        viewY: -Math.sin(ang),
1080	      };
1081	    }
1082	  }
1083	}
