1085	function elevationViewPlanThree(
1086	  ev: Extract<Element, { kind: 'elevation_view' }>,
1087	  elementsById: Record<string, Element>,
1088	): THREE.Group {
1089	  const group = new THREE.Group();
1090	  group.userData.bimPickId = ev.id;
1091	  group.userData.bimElevationViewId = ev.id;
1092	
1093	  const bounds = modelXyBoundsMm(elementsById) ?? {
1094	    minXmm: -5000,
1095	    minYmm: -5000,
1096	    maxXmm: 5000,
1097	    maxYmm: 5000,
1098	  };
1099	  const { anchorXmm, anchorYmm, viewX, viewY } = elevationMarkerAnchorMm(ev, bounds);
1100	
1101	  const ax = ux(anchorXmm);
1102	  const az = uz(anchorYmm);
1103	  const Y = PLAN_Y + 0.008;
1104	  const color = readToken('--cat-section', '#ef4444');
1105	
1106	  // Triangle pointing in the view direction (toward the model).
1107	  const TRI_LEN = 0.6;
1108	  const TRI_HALF = 0.35;
1109	  // Tangent perpendicular to view direction in plan (right-hand).
1110	  const tx = -viewY;
1111	  const ty = viewX;
1112	  const tipX = ax + viewX * TRI_LEN;
1113	  const tipZ = az + viewY * TRI_LEN;
1114	  const baseLx = ax + tx * TRI_HALF;
1115	  const baseLz = az + ty * TRI_HALF;
1116	  const baseRx = ax - tx * TRI_HALF;
