1173	/** D2: renders the 4-quadrant circle plan symbol for an interior_elevation_marker. */
1174	function interiorElevationMarkerPlanThree(
1175	  iem: Extract<Element, { kind: 'interior_elevation_marker' }>,
1176	): THREE.Group {
1177	  const group = new THREE.Group();
1178	  group.userData.bimPickId = iem.id;
1179	
1180	  const cx = ux(iem.positionMm.xMm);
1181	  const cz = uz(iem.positionMm.yMm);
1182	  const Y = PLAN_Y + 0.0085;
1183	  const color = readToken('--cat-section', '#ef4444');
1184	  const R = 0.28;
1185	  const segs = 48;
1186	
1187	  // Outer circle
1188	  const circPts: THREE.Vector3[] = [];
1189	  for (let i = 0; i <= segs; i++) {
1190	    const a = (i / segs) * Math.PI * 2;
1191	    circPts.push(new THREE.Vector3(cx + Math.cos(a) * R, Y, cz + Math.sin(a) * R));
1192	  }
1193	  const circleLine = new THREE.Line(
1194	    new THREE.BufferGeometry().setFromPoints(circPts),
1195	    new THREE.LineBasicMaterial({ color, depthTest: false }),
1196	  );
1197	  circleLine.renderOrder = 991;
1198	  group.add(circleLine);
1199	
1200	  // Cross dividers creating the 4-quadrant look
1201	  const mat = new THREE.LineBasicMaterial({ color, depthTest: false });
1202	  const hLine = new THREE.Line(
1203	    new THREE.BufferGeometry().setFromPoints([
1204	      new THREE.Vector3(cx - R, Y, cz),
1205	      new THREE.Vector3(cx + R, Y, cz),
1206	    ]),
1207	    mat,
1208	  );
1209	  const vLine = new THREE.Line(
1210	    new THREE.BufferGeometry().setFromPoints([
1211	      new THREE.Vector3(cx, Y, cz - R),
1212	      new THREE.Vector3(cx, Y, cz + R),
1213	    ]),
1214	    mat,
1215	  );
1216	  hLine.renderOrder = 991;
1217	  vLine.renderOrder = 991;
1218	  group.add(hLine, vLine);
1219	
1220	  // Four inward-pointing arrows (N/S/E/W)
1221	  const ARROW = 0.14;
1222	  const ARROW_HALF = 0.07;
1223	  const dirs: Array<{ vx: number; vz: number }> = [
1224	    { vx: 0, vz: -1 },
1225	    { vx: 0, vz: 1 },
1226	    { vx: 1, vz: 0 },
1227	    { vx: -1, vz: 0 },
1228	  ];
1229	  for (const { vx, vz } of dirs) {
1230	    const tx = -vz;
1231	    const tz = vx;
1232	    const tipX = cx + vx * R;
1233	    const tipZ = cz + vz * R;
1234	    const baseX = cx + vx * (R - ARROW);
1235	    const baseZ = cz + vz * (R - ARROW);
1236	    const arrowLine = new THREE.Line(
1237	      new THREE.BufferGeometry().setFromPoints([
1238	        new THREE.Vector3(baseX + tx * ARROW_HALF, Y, baseZ + tz * ARROW_HALF),
1239	        new THREE.Vector3(tipX, Y, tipZ),
1240	        new THREE.Vector3(baseX - tx * ARROW_HALF, Y, baseZ - tz * ARROW_HALF),
1241	      ]),
1242	      new THREE.LineBasicMaterial({ color, depthTest: false }),
1243	    );
1244	    arrowLine.renderOrder = 991;
1245	    group.add(arrowLine);
1246	  }
1247	
1248	  return group;
1249	}
