1251	function sectionCutPlanThree(sc: Extract<Element, { kind: 'section_cut' }>): THREE.Group {
1252	  const group = new THREE.Group();
1253	  group.userData.bimPickId = sc.id;
1254	
1255	  const sx = ux(sc.lineStartMm.xMm);
1256	  const sz = uz(sc.lineStartMm.yMm);
1257	  const ex = ux(sc.lineEndMm.xMm);
1258	  const ez = uz(sc.lineEndMm.yMm);
1259	  const Y = PLAN_Y + 0.007;
1260	  const color = readToken('--cat-section', '#ef4444');
1261	
1262	  // Dashed cut body
1263	  const linePts = [new THREE.Vector3(sx, Y, sz), new THREE.Vector3(ex, Y, ez)];
1264	  const lineGeom = new THREE.BufferGeometry().setFromPoints(linePts);
1265	  const lineMat = new THREE.LineDashedMaterial({ color, dashSize: 0.35, gapSize: 0.14 });
1266	  const line = new THREE.Line(lineGeom, lineMat);
1267	  line.computeLineDistances();
1268	  group.add(line);
1269	
1270	  // Direction along cut and right-hand perpendicular (view direction).
1271	  const dx = ex - sx;
1272	  const dz = ez - sz;
1273	  const len = Math.max(0.001, Math.hypot(dx, dz));
1274	  const nx = dx / len;
1275	  const nz = dz / len;
1276	  const vx = nz;
1277	  const vz = -nx;
1278	
1279	  const STUB = 0.25;
1280	  const ARROW = 0.55;
1281	  for (const [px, pz] of [
1282	    [sx, sz],
1283	    [ex, ez],
1284	  ] as [number, number][]) {
1285	    const stubPts = [
1286	      new THREE.Vector3(px - nz * STUB, Y, pz + nx * STUB),
1287	      new THREE.Vector3(px + nz * STUB, Y, pz - nx * STUB),
1288	    ];
1289	    group.add(
1290	      new THREE.Line(
1291	        new THREE.BufferGeometry().setFromPoints(stubPts),
1292	        new THREE.LineBasicMaterial({ color }),
1293	      ),
1294	    );
1295	    const arrPts = [
1296	      new THREE.Vector3(px, Y, pz),
1297	      new THREE.Vector3(px + vx * ARROW, Y, pz + vz * ARROW),
1298	    ];
1299	    group.add(
1300	      new THREE.Line(
1301	        new THREE.BufferGeometry().setFromPoints(arrPts),
1302	        new THREE.LineBasicMaterial({ color }),
1303	      ),
1304	    );
1305	  }
1306	
1307	  return group;
1308	}
