1318	  const Y = PLAN_Y + 0.006;
1319	  const color = readToken('--plan-wall', '#1c1917');
1320	  const solidMat = new THREE.LineBasicMaterial({ color });
1321	  const dashedMat = new THREE.LineDashedMaterial({ color, dashSize: 0.06, gapSize: 0.04 });
1322	
1323	  const hw = bM / 2;
1324	  const hh = hM / 2;
1325	  const rectPts = [
1326	    new THREE.Vector3(cx - hw, Y, cz - hh),
1327	    new THREE.Vector3(cx + hw, Y, cz - hh),
1328	    new THREE.Vector3(cx + hw, Y, cz + hh),
1329	    new THREE.Vector3(cx - hw, Y, cz + hh),
1330	    new THREE.Vector3(cx - hw, Y, cz - hh),
1331	  ];
1332	  grp.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(rectPts), solidMat));
1333	  grp.add(
1334	    new THREE.Line(
1335	      new THREE.BufferGeometry().setFromPoints([
1336	        new THREE.Vector3(cx - hw, Y, cz - hh),
1337	        new THREE.Vector3(cx + hw, Y, cz + hh),
1338	      ]),
1339	      solidMat,
1340	    ),
1341	  );
1342	  grp.add(
1343	    new THREE.Line(
1344	      new THREE.BufferGeometry().setFromPoints([
1345	        new THREE.Vector3(cx + hw, Y, cz - hh),
1346	        new THREE.Vector3(cx - hw, Y, cz + hh),
1347	      ]),
1348	      solidMat,
1349	    ),
1350	  );
1351	
1352	  const txM = (col.topOffsetXMm ?? 0) / 1000;
1353	  const tzM = (col.topOffsetYMm ?? 0) / 1000;
1354	  if (txM !== 0 || tzM !== 0) {
1355	    const tcx = cx + txM;
1356	    const tcz = cz + tzM;
1357	    const topRect = new THREE.Line(
1358	      new THREE.BufferGeometry().setFromPoints([
1359	        new THREE.Vector3(tcx - hw, Y, tcz - hh),
1360	        new THREE.Vector3(tcx + hw, Y, tcz - hh),
1361	        new THREE.Vector3(tcx + hw, Y, tcz + hh),
1362	        new THREE.Vector3(tcx - hw, Y, tcz + hh),
1363	        new THREE.Vector3(tcx - hw, Y, tcz - hh),
1364	      ]),
1365	      dashedMat,
1366	    );
1367	    topRect.computeLineDistances();
1368	    grp.add(topRect);
1369	    const axisLine = new THREE.Line(
1370	      new THREE.BufferGeometry().setFromPoints([
1371	        new THREE.Vector3(cx, Y, cz),
1372	        new THREE.Vector3(tcx, Y, tcz),
1373	      ]),
1374	      dashedMat,
1375	    );
