 *
 * Works entirely in local wall space (X along wall axis, Z across thickness)
 * before the caller applies the world-space rotation.  Lines follow z = x + c
 * (slope +1) at evenly-spaced c values.
 */
function buildWallCutHatch(
  len: number,
  thick: number,
  sx: number,
  sz: number,
  nx: number,
  nz: number,
