    color: string;
    shadowMapSize: number;
  };
  /** Hemisphere light split between sky and ground. */
  hemi: {
    intensity: number;
    skyColor: string;
    groundColor: string;
  };
  ssao: {
    kernelRadius: number;
    minDistance: number;
    maxDistance: number;
  };
}

