2278	/**
2279	 * Local helper: build a sub-divided sloped-top prism geometry.
2280	 * Local frame: x along segment (-halfL..+halfL), y up (0..h_at_step),
2281	 * z perpendicular to segment (-halfT..+halfT). The mesh is sized in m;
2282	 * the caller positions + rotates it into world space.
2283	 *
2284	 * `topHeightsRelM` is the sloped-top profile, sampled at each of N+1
2285	 * uniform steps along the segment. Heights are RELATIVE to the prism's
2286	 * y-base (i.e., wall-top height minus yBase). The bottom face is flat;
2287	 * the top, front, back faces follow the per-step heights so a wall
2288	 * crossing an asymmetric_gable ridge resolves a clean kink at the
2289	 * ridge crossing instead of a single straight slope.
2290	 */
2291	function buildSlopedSegmentGeometry(
2292	  segLenM: number,
2293	  thickM: number,
2294	  topHeightsRelM: number[],
2295	): THREE.BufferGeometry {
2296	  const N = topHeightsRelM.length - 1;
2297	  const halfL = segLenM / 2;
2298	  const halfT = thickM / 2;
2299	
2300	  // 4 vertices per step: (front-base, back-base, front-top, back-top).
2301	  const positions: number[] = [];
2302	  for (let i = 0; i <= N; i++) {
2303	    const x = -halfL + (i / N) * segLenM;
2304	    const h = Math.max(0.001, topHeightsRelM[i]);
2305	    positions.push(x, 0, +halfT); // 4i+0 front-base
2306	    positions.push(x, 0, -halfT); // 4i+1 back-base
2307	    positions.push(x, h, +halfT); // 4i+2 front-top
2308	    positions.push(x, h, -halfT); // 4i+3 back-top
2309	  }
2310	
2311	  const indices: number[] = [];
2312	  for (let i = 0; i < N; i++) {
2313	    const a = i * 4;
2314	    const b = (i + 1) * 4;
2315	    // front face (z = +halfT): outward normal +Z
2316	    indices.push(a + 0, b + 0, b + 2);
2317	    indices.push(a + 0, b + 2, a + 2);
2318	    // back face (z = -halfT): outward normal -Z (reverse winding)
2319	    indices.push(a + 1, a + 3, b + 3);
