function buildWallPartPlanFills(
  wall: Extract<Element, { kind: 'wall' }>,
  len: number,
  sx: number,
  sz: number,
  nx: number,
  nz: number,
  angle: number,
  thick: number,
  perpX: number,
  perpZ: number,
  elementsById?: Record<string, Element>,
): THREE.Mesh[] | null {
  if (!wall.parts || wall.parts.length === 0) return null;
  const fills: THREE.Mesh[] = [];
  for (const part of wall.parts) {
    const partLen = (part.endT - part.startT) * len;
    if (partLen < 1e-6) continue;
    const partCenterAlong = ((part.startT + part.endT) / 2) * len;
    const color = materialPlanShadedColor(part.materialId, elementsById);
    const geom = new THREE.BoxGeometry(partLen, PLAN_WALL_CENTER_SLICE_HEIGHT_M, thick);
    const mat = new THREE.MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 0.4,
      depthWrite: false,
    });
    const fill = new THREE.Mesh(geom, mat);
    fill.position.set(
      sx + nx * partCenterAlong + perpX,
      PLAN_Y + 0.0005,
      sz + nz * partCenterAlong + perpZ,
    );
    fill.rotation.y = -angle;
    fill.userData.bimPickId = wall.id;
    fill.userData.partId = part.id;
    fills.push(fill);
  }
  return fills.length > 0 ? fills : null;
}

export function planWallMesh(
  wall: Extract<Element, { kind: 'wall' }>,
  selectedId?: string,
  lineWeightScale = 1,
  elementsById?: Record<string, Element>,
  detailLevel: PlanDetailLevel = 'medium',
): THREE.Object3D {
