    InspectorPropertiesFor(win, t, {
      onPropertyChange,
      elementsById: { 'mat-glass-1': glassMat },
    }),
  );
  const select = getByTestId('inspector-window-glazing-material') as HTMLSelectElement;
  fireEvent.change(select, { target: { value: 'mat-glass-1' } });

